import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { getApiUrl } from '../config/apiConfig';
import { isLonguenesseSite, getSiteKey } from '../config/site';
import './Sidebar.css';

const Sidebar = () => {
  // Étendu par défaut sur desktop (largeur > 768px) pour éviter que le menu semble "disparaître" au refresh
  const [isExpanded, setIsExpanded] = useState(() => typeof window !== 'undefined' && window.innerWidth > 768);
  const isLonguenesse = isLonguenesseSite();
  const storageSuffix = getSiteKey();
  const [socialMenuExpanded, setSocialMenuExpanded] = useState(() => {
    try {
      return localStorage.getItem(`sidebar:${storageSuffix}:socialExpanded`) === '1';
    } catch {
      return false;
    }
  });
  const [planningMenuExpanded, setPlanningMenuExpanded] = useState(() => {
    try {
      return localStorage.getItem(`sidebar:${storageSuffix}:planningExpanded`) === '1';
    } catch {
      return false;
    }
  });
  const [venteMenuExpanded, setVenteMenuExpanded] = useState(() => {
    try {
      return localStorage.getItem(`sidebar:${storageSuffix}:venteExpanded`) === '1';
    } catch {
      return false;
    }
  });
  const [paiesMenuExpanded, setPaiesMenuExpanded] = useState(() => {
    try {
      return localStorage.getItem(`sidebar:${storageSuffix}:paiesExpanded`) === '1';
    } catch {
      return false;
    }
  });
  const [facturationMenuExpanded, setFacturationMenuExpanded] = useState(() => {
    try {
      return localStorage.getItem(`sidebar:${storageSuffix}:facturationExpanded`) === '1';
    } catch {
      return false;
    }
  });
  /**
   * Groupe « Stocks » : même structure Arras (/plan) et Longuenesse (/lon) — parent + sous-menus.
   * Clé v2 : évite un ancien état « replié » sur Lon qui ne montrait que le bouton parent (sans sous-menu visible).
   */
  const [stocksMenuExpanded, setStocksMenuExpanded] = useState(() => {
    try {
      const v = localStorage.getItem(`sidebar:${storageSuffix}:stocksGroupExpanded`);
      if (v === null) return true;
      return v === '1';
    } catch {
      return true;
    }
  });
  const [menuPermissions, setMenuPermissions] = useState([]);
  const location = useLocation();
  const { user, isAdmin, isEmployee } = useAuth();

  // Sous-menus admin (comme Social) — regroupent des entrées retirées du menu plat pour l’admin uniquement
  const PLANNING_MENU_ITEMS = [
    { path: '/planning', label: 'Génération du planning', icon: '🎯', menuId: 'planning' },
    { path: '/constraints', label: 'Contraintes hebdomadaires', icon: '📋', menuId: 'constraints' }
  ];

  const VENTE_MENU_ITEMS = [
    { path: '/sales-stats', label: 'Stats Vente', icon: '💰', menuId: 'sales-stats' },
    { path: '/ambassadeur', label: 'Ambassadeur', icon: '⭐', menuId: 'ambassadeur' },
    { path: '/plateaux-repas', label: 'Plateaux repas', icon: '🍽️', menuId: 'plateaux-repas' },
    { path: '/commandes-en-ligne', label: 'Commandes en ligne', icon: '🛒', menuId: 'commandes-en-ligne' },
    { path: '/commande-livraison', label: 'Commande livraison', icon: '🚚', menuId: 'commande-livraison', longuenesseOnly: true }
  ];

  const PAIES_MENU_ITEMS = [
    { path: '/km-expenses', label: 'Frais KM', icon: '🚗', menuId: 'km-expenses' },
    { path: '/meal-expenses', label: 'Frais repas', icon: '🍽️', menuId: 'meal-expenses' }
  ];

  const FACTURATION_MENU_ITEMS = [
    { path: '/ticket-restaurant', label: 'Ticket restaurant', icon: '🎫', menuId: 'ticket-restaurant' },
    { path: '/product-exchanges', label: 'Échanges entre boulangeries', icon: '🔄', menuId: 'product-exchanges' },
    { path: '/chorus', label: 'Chorus', icon: '🎵', menuId: 'chorus', longuenesseOnly: true },
    { path: '/compte-client-depots', label: 'Dépôts compte client', icon: '💳', menuId: 'compte-client-depots', longuenesseOnly: true }
  ];

  /** Liens communs sous la rubrique « Stocks » (admin — même UX Arras / Longuenesse). */
  const STOCKS_MENU_ITEMS_COMMON = [
    { path: '/stocks', label: 'Stocks farines', icon: '📦', menuId: 'stocks' },
    { path: '/positive', label: 'Positive (IA)', icon: '📷', menuId: 'positive' },
    { path: '/commande-tgt', label: 'Commande TGT', icon: '🛒', menuId: 'commande-tgt' }
  ];
  /** Entrées admin supplémentaires uniquement sur Longuenesse (future évolution ; tableau vide = menu identique à Arras). */
  const STOCKS_MENU_ITEMS_LON_EXTRA = [];

  const STOCKS_MENU_ITEMS = [
    ...STOCKS_MENU_ITEMS_COMMON,
    ...(isLonguenesse ? STOCKS_MENU_ITEMS_LON_EXTRA : [])
  ];

  const ADMIN_GROUPED_MENU_IDS = new Set(
    [...PLANNING_MENU_ITEMS, ...VENTE_MENU_ITEMS, ...PAIES_MENU_ITEMS, ...FACTURATION_MENU_ITEMS, ...STOCKS_MENU_ITEMS].map(
      (i) => i.menuId
    )
  );

  // Menus regroupés sous "Social" (visible uniquement pour l'admin)
  const SOCIAL_MENU_ITEMS = [
    { path: '/advance-requests', label: 'Demandes d\'Acompte', icon: '💰', menuId: 'advance-requests' },
    { path: '/vacation-management', label: 'Gestion des Congés', icon: '🏖️', menuId: 'vacation-management' },
    { path: '/sick-leave-management', label: 'Gestion des Arrêts Maladie', icon: '🏥', menuId: 'sick-leave-management' },
    { path: '/mutuelle-management', label: 'Gestion des Mutuelles', icon: '🏥', menuId: 'mutuelle-management' },
    { path: '/primes', label: 'Primes', icon: '💰', menuId: 'primes' }
  ];

  // Permissions par défaut en cas d'erreur API
  const getDefaultMenuPermissions = (role) => {
    if (role === 'admin') {
      return [
        { menuId: 'dashboard', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'employees', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'constraints', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'planning', isVisibleToAdmin: true, isVisibleToEmployee: true },
        { menuId: 'sales-stats', isVisibleToAdmin: true, isVisibleToEmployee: true },
        { menuId: 'absences', isVisibleToAdmin: true, isVisibleToEmployee: true },
        { menuId: 'meal-expenses', isVisibleToAdmin: true, isVisibleToEmployee: true },
        { menuId: 'km-expenses', isVisibleToAdmin: true, isVisibleToEmployee: true },
        { menuId: 'recup', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'primes', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'employee-status-print', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'parameters', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'stocks', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'positive', isVisibleToAdmin: true, isVisibleToEmployee: true },
        { menuId: 'commande-tgt', isVisibleToAdmin: true, isVisibleToEmployee: true },
        { menuId: 'sick-leave-management', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'mutuelle-management', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'vacation-management', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'ticket-restaurant', isVisibleToAdmin: true, isVisibleToEmployee: true },
        { menuId: 'advance-requests', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'employee-dashboard', isVisibleToAdmin: false, isVisibleToEmployee: true },
        { menuId: 'ambassadeur', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'commandes-en-ligne', isVisibleToAdmin: true, isVisibleToEmployee: true },
        { menuId: 'commande-livraison', isVisibleToAdmin: true, isVisibleToEmployee: true },
        { menuId: 'product-exchanges', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'frais-km-responsable', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'plateaux-repas', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'chorus', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'compte-client-depots', isVisibleToAdmin: true, isVisibleToEmployee: false },
        { menuId: 'vehicle', isVisibleToAdmin: true, isVisibleToEmployee: false }
      ];
    } else {
      // Fallback salarié : permissions restrictives (planning, km-expenses, ticket-restaurant masqués par défaut pour Longuenesse)
      // Ces valeurs ne s'appliquent qu'en cas d'erreur API ; sinon l'API fait foi
      return [
        { menuId: 'dashboard', isVisibleToAdmin: false, isVisibleToEmployee: true },
        { menuId: 'planning', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'sales-stats', isVisibleToAdmin: false, isVisibleToEmployee: true },
        { menuId: 'absences', isVisibleToAdmin: false, isVisibleToEmployee: true },
        { menuId: 'meal-expenses', isVisibleToAdmin: false, isVisibleToEmployee: true },
        { menuId: 'km-expenses', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'recup', isVisibleToAdmin: false, isVisibleToEmployee: true },
        { menuId: 'ticket-restaurant', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'advance-requests', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'vacation-management', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'sick-leave-management', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'mutuelle-management', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'primes', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'ambassadeur', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'commandes-en-ligne', isVisibleToAdmin: false, isVisibleToEmployee: true },
        { menuId: 'commande-livraison', isVisibleToAdmin: false, isVisibleToEmployee: true },
        { menuId: 'positive', isVisibleToAdmin: false, isVisibleToEmployee: true },
        { menuId: 'product-exchanges', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'frais-km-responsable', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'plateaux-repas', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'chorus', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'compte-client-depots', isVisibleToAdmin: false, isVisibleToEmployee: false },
        { menuId: 'vehicle', isVisibleToAdmin: false, isVisibleToEmployee: false }
      ];
    }
  };

  // Auto-expandre les sous-menus admin quand on est sur une de leurs pages
  useEffect(() => {
    const p = location.pathname;
    if (PLANNING_MENU_ITEMS.some((i) => p.includes(i.path))) setPlanningMenuExpanded(true);
    if (VENTE_MENU_ITEMS.some((i) => p.includes(i.path))) setVenteMenuExpanded(true);
    if (PAIES_MENU_ITEMS.some((i) => p.includes(i.path))) setPaiesMenuExpanded(true);
    if (FACTURATION_MENU_ITEMS.some((i) => p.includes(i.path))) setFacturationMenuExpanded(true);
    if (STOCKS_MENU_ITEMS.some((i) => p.includes(i.path))) setStocksMenuExpanded(true);
    const socialPaths = ['advance-requests', 'vacation-management', 'sick-leave-management', 'mutuelle-management', 'primes'];
    if (socialPaths.some((x) => p.includes(x))) setSocialMenuExpanded(true);
  }, [location.pathname]);

  // Persister l'état des sous-menus (évite "menu disparu" après refresh si le groupe était ouvert)
  useEffect(() => {
    try {
      localStorage.setItem(`sidebar:${storageSuffix}:socialExpanded`, socialMenuExpanded ? '1' : '0');
      localStorage.setItem(`sidebar:${storageSuffix}:planningExpanded`, planningMenuExpanded ? '1' : '0');
      localStorage.setItem(`sidebar:${storageSuffix}:venteExpanded`, venteMenuExpanded ? '1' : '0');
      localStorage.setItem(`sidebar:${storageSuffix}:paiesExpanded`, paiesMenuExpanded ? '1' : '0');
      localStorage.setItem(`sidebar:${storageSuffix}:facturationExpanded`, facturationMenuExpanded ? '1' : '0');
      localStorage.setItem(`sidebar:${storageSuffix}:stocksGroupExpanded`, stocksMenuExpanded ? '1' : '0');
    } catch {
      /* ignore */
    }
  }, [
    storageSuffix,
    socialMenuExpanded,
    planningMenuExpanded,
    venteMenuExpanded,
    paiesMenuExpanded,
    facturationMenuExpanded,
    stocksMenuExpanded
  ]);

  // Charger les permissions de menu selon le rôle utilisateur
  useEffect(() => {
    const loadMenuPermissions = async () => {
      if (!user) return;

      try {
        const apiBaseUrl = getApiUrl();
        const response = await fetch(`${apiBaseUrl}/menu-permissions?role=${user.role}`);
        
        // Vérifier si la réponse est du JSON
        const contentType = response.headers.get('content-type');
        if (!contentType || !contentType.includes('application/json')) {
          console.warn('⚠️ API non disponible, utilisation des permissions par défaut');
          // Utiliser des permissions par défaut en cas d'erreur API
          setMenuPermissions(getDefaultMenuPermissions(user.role));
          return;
        }
        
        const data = await response.json();
        
        if (data.success && Array.isArray(data.menuPermissions)) {
          const defaults = getDefaultMenuPermissions(user.role);
          const apiPerms = data.menuPermissions;
          const menuIdsFromApi = new Set(apiPerms.map(p => p.menuId));
          const merged = [...apiPerms];
          for (const def of defaults) {
            if (!menuIdsFromApi.has(def.menuId)) {
              // Pour les salariés : si l'API n'a pas retourné un menu, c'est qu'il n'est pas autorisé
              // (l'API filtre par isVisibleToEmployee). Ne pas ajouter de défaut qui accorderait l'accès.
              if (user.role === 'employee') {
                merged.push({ ...def, isVisibleToEmployee: false });
              } else {
                merged.push(def);
              }
            }
          }
          setMenuPermissions(merged);
          console.log('📋 Permissions de menu chargées:', merged.length, 'menus');
        } else {
          console.warn('⚠️ Erreur API ou données invalides, utilisation des permissions par défaut');
          setMenuPermissions(getDefaultMenuPermissions(user.role));
        }
      } catch (error) {
        console.error('❌ Erreur lors du chargement des permissions:', error);
        console.warn('⚠️ Utilisation des permissions par défaut');
        setMenuPermissions(getDefaultMenuPermissions(user.role));
      }
    };

    loadMenuPermissions();
  }, [user]);


  // Menu items avec permissions (sans les items Social - regroupés séparément)
  const menuItems = [
    { path: '/dashboard', label: 'Tableau de bord', icon: '📊', menuId: 'dashboard' },
    { path: '/employees', label: 'Gestion des employés', icon: '👥', menuId: 'employees' },
    { path: '/constraints', label: 'Contraintes hebdomadaires', icon: '📋', menuId: 'constraints' },
    { path: '/planning', label: 'Génération du planning', icon: '🎯', menuId: 'planning' },
    { path: '/sales-stats', label: 'Stats Vente', icon: '💰', menuId: 'sales-stats' },
    { path: '/absences', label: 'État des absences', icon: '📈', menuId: 'absences' },
    { path: '/meal-expenses', label: 'Frais Repas', icon: '🍽️', menuId: 'meal-expenses' },
    { path: '/km-expenses', label: 'Frais KM', icon: '🚗', menuId: 'km-expenses' },
    { path: '/recup', label: 'Heures de récup', icon: '⏱️', menuId: 'recup' },
    { path: '/employee-status-print', label: 'Imprimer État', icon: '🖨️', menuId: 'employee-status-print' },
    { path: '/parameters', label: 'Paramètres', icon: '⚙️', menuId: 'parameters' },
    { path: '/ticket-restaurant', label: 'Ticket restaurant', icon: '🎫', menuId: 'ticket-restaurant' },
    { path: '/employee-dashboard', label: 'Mes Documents', icon: '📁', menuId: 'employee-dashboard' },
    { path: '/ambassadeur', label: 'Ambassadeur', icon: '⭐', menuId: 'ambassadeur' },
    { path: '/commandes-en-ligne', label: 'Commandes en ligne', icon: '🛒', menuId: 'commandes-en-ligne' },
    { path: '/commande-livraison', label: 'Commande livraison', icon: '🚚', menuId: 'commande-livraison', longuenesseOnly: true },
    { path: '/product-exchanges', label: 'Échanges entre boulangeries', icon: '🔄', menuId: 'product-exchanges' },
    { path: '/frais-km-responsable', label: 'Frais KM Responsable', icon: '🚗', menuId: 'frais-km-responsable' },
    { path: '/plateaux-repas', label: 'Plateaux repas', icon: '🍽️', menuId: 'plateaux-repas' },
    { path: '/chorus', label: 'Chorus', icon: '🎵', menuId: 'chorus', longuenesseOnly: true },
    { path: '/vehicle', label: 'Véhicule', icon: '🚗', menuId: 'vehicle' },
    { path: '/positive', label: 'Positive (IA)', icon: '📷', menuId: 'positive' }
  ];

  // Vérifier si un menu a la permission pour le rôle actuel
  const hasPermission = (menuId) => {
    if (!user) return false;

    // Frais KM Responsable / Véhicule / Stocks : toujours visibles pour l’admin (évite masquage si permission BDD absente ou désactivée par erreur)
    if (
      isAdmin() &&
      (menuId === 'frais-km-responsable' ||
        menuId === 'vehicle' ||
        menuId === 'compte-client-depots' ||
        menuId === 'stocks')
    )
      return true;

    // Permissions pas encore chargées : éviter menu vide (sous-menus + Véhicule invisibles)
    if (menuPermissions.length === 0) {
      const defaults = getDefaultMenuPermissions(user.role);
      const d = defaults.find((p) => p.menuId === menuId);
      if (d) {
        return isAdmin() ? d.isVisibleToAdmin : d.isVisibleToEmployee;
      }
      return false;
    }

    const permission = menuPermissions.find((p) => p.menuId === menuId);
    if (permission) {
      return isAdmin() ? permission.isVisibleToAdmin : permission.isVisibleToEmployee;
    }

    // Nouveau menuId pas encore en base : fallback défauts admin uniquement
    if (isAdmin()) {
      const defaults = getDefaultMenuPermissions('admin');
      const d = defaults.find((p) => p.menuId === menuId);
      if (d) return d.isVisibleToAdmin;
    }
    return false;
  };

  /** Sous-menus admin : afficher tous les liens (sauf Chorus hors Longuenesse). Les pages restent protégées par les routes. */
  const filterSubmenuForAdmin = (items) =>
    items.filter((item) => !(item.longuenesseOnly && !isLonguenesse));

  /**
   * Entrées sous « Stocks » selon les permissions menu.
   * Pour les salariés, « Positive (IA) » reste dans le menu plat : on ne le duplique pas sous Stocks.
   */
  const visibleStocksSubitems = filterSubmenuForAdmin(STOCKS_MENU_ITEMS).filter((item) => {
    if (!hasPermission(item.menuId)) return false;
    if (isEmployee() && item.menuId === 'positive') return false;
    return true;
  });

  // Filtrer les menus principaux ; pour l’admin, retirer les entrées regroupées (Vente, Paies, Facturation)
  const getFilteredMenuItems = () => {
    if (!user) return [];

    let items = menuItems.filter((item) => !(item.longuenesseOnly && !isLonguenesse));
    items = items.filter((item) => hasPermission(item.menuId));

    if (isAdmin()) {
      items = items.filter((item) => !ADMIN_GROUPED_MENU_IDS.has(item.menuId));
    }

    return items;
  };

  // Items du menu Social visibles pour le salarié (affichés individuellement, pas sous un parent)
  const getSocialItemsForEmployee = () => {
    if (!isEmployee()) return [];
    return SOCIAL_MENU_ITEMS.filter(item => hasPermission(item.menuId));
  };

  const handleMouseEnter = () => {
    setIsExpanded(true);
  };

  const handleMouseLeave = () => {
    // Sur desktop, ne pas auto-replier : sur certains appareils (ou au refresh)
    // cela donne l’impression que des menus "disparaissent".
    if (typeof window !== 'undefined' && window.innerWidth <= 768) {
      setIsExpanded(false);
    }
  };


  return (
    <div 
      className={`sidebar ${isExpanded ? 'expanded' : 'collapsed'}`}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
    >
      <div className="sidebar-header">
        <div className="logo-container">
          <div className="filmara-logo-sidebar">
            <div className="logo-symbol">
              <div className="orca-element"></div>
              <div className="fox-element"></div>
            </div>
            <div className="logo-text">FILMARA</div>
          </div>
        </div>
        <div className="sidebar-title">Boulangerie</div>
      </div>
      
      <nav className="sidebar-nav">
        {getFilteredMenuItems().map((item) => (
          <Link
            key={item.path}
            to={item.path}
            className={`nav-item ${location.pathname === item.path ? 'active' : ''}`}
          >
            <span className="nav-icon">{item.icon}</span>
            <span className="nav-label">{item.label}</span>
          </Link>
        ))}
        {/* Sous-menu admin : Planning */}
        {isAdmin() && filterSubmenuForAdmin(PLANNING_MENU_ITEMS).length > 0 && (
          <div className="nav-group admin-submenu">
            <button
              type="button"
              className={`nav-item nav-group-toggle ${planningMenuExpanded ? 'expanded' : ''} ${PLANNING_MENU_ITEMS.some((i) => location.pathname.includes(i.path)) ? 'active' : ''}`}
              onClick={() => {
                setIsExpanded(true);
                setPlanningMenuExpanded((v) => !v);
              }}
              onMouseEnter={() => isExpanded && setPlanningMenuExpanded(true)}
            >
              <span className="nav-icon">📅</span>
              <span className="nav-label">Planning</span>
              <span className="nav-chevron">{planningMenuExpanded ? '▼' : '▶'}</span>
            </button>
            {planningMenuExpanded && (
              <div className="nav-submenu">
                {filterSubmenuForAdmin(PLANNING_MENU_ITEMS).map((item) => (
                  <Link
                    key={item.path}
                    to={item.path}
                    className={`nav-item nav-subitem ${location.pathname.includes(item.path) ? 'active' : ''}`}
                  >
                    <span className="nav-icon">{item.icon}</span>
                    <span className="nav-label">{item.label}</span>
                  </Link>
                ))}
              </div>
            )}
          </div>
        )}
        {/* Sous-menu Stocks : admin toujours ; salarié si permission menu (ex. Stocks farines — Longuenesse / Arras). */}
        {(isAdmin() || isEmployee()) && visibleStocksSubitems.length > 0 && (
          <div className="nav-group admin-submenu">
            <button
              type="button"
              className={`nav-item nav-group-toggle ${stocksMenuExpanded ? 'expanded' : ''} ${STOCKS_MENU_ITEMS.some((i) => location.pathname.includes(i.path)) ? 'active' : ''}`}
              onClick={() => {
                setIsExpanded(true);
                setStocksMenuExpanded((v) => !v);
              }}
              onMouseEnter={() => isExpanded && setStocksMenuExpanded(true)}
            >
              <span className="nav-icon">📦</span>
              <span className="nav-label">Stocks</span>
              <span className="nav-chevron">{stocksMenuExpanded ? '▼' : '▶'}</span>
            </button>
            {stocksMenuExpanded && (
              <div className="nav-submenu">
                {visibleStocksSubitems.map((item) => (
                  <Link
                    key={item.path}
                    to={item.path}
                    className={`nav-item nav-subitem ${location.pathname.includes(item.path) ? 'active' : ''}`}
                  >
                    <span className="nav-icon">{item.icon}</span>
                    <span className="nav-label">{item.label}</span>
                  </Link>
                ))}
              </div>
            )}
          </div>
        )}
        {/* Sous-menus admin : Vente, Paies, Facturation */}
        {isAdmin() && filterSubmenuForAdmin(VENTE_MENU_ITEMS).length > 0 && (
          <div className="nav-group admin-submenu">
            <button
              type="button"
              className={`nav-item nav-group-toggle ${venteMenuExpanded ? 'expanded' : ''} ${VENTE_MENU_ITEMS.some((i) => location.pathname.includes(i.path)) ? 'active' : ''}`}
              onClick={() => {
                setIsExpanded(true);
                setVenteMenuExpanded((v) => !v);
              }}
              onMouseEnter={() => isExpanded && setVenteMenuExpanded(true)}
            >
              <span className="nav-icon">📊</span>
              <span className="nav-label">Vente</span>
              <span className="nav-chevron">{venteMenuExpanded ? '▼' : '▶'}</span>
            </button>
            {venteMenuExpanded && (
              <div className="nav-submenu">
                {filterSubmenuForAdmin(VENTE_MENU_ITEMS).map((item) => (
                  <Link
                    key={item.path}
                    to={item.path}
                    className={`nav-item nav-subitem ${location.pathname.includes(item.path) ? 'active' : ''}`}
                  >
                    <span className="nav-icon">{item.icon}</span>
                    <span className="nav-label">{item.label}</span>
                  </Link>
                ))}
              </div>
            )}
          </div>
        )}
        {isAdmin() && filterSubmenuForAdmin(PAIES_MENU_ITEMS).length > 0 && (
          <div className="nav-group admin-submenu">
            <button
              type="button"
              className={`nav-item nav-group-toggle ${paiesMenuExpanded ? 'expanded' : ''} ${PAIES_MENU_ITEMS.some((i) => location.pathname.includes(i.path)) ? 'active' : ''}`}
              onClick={() => {
                setIsExpanded(true);
                setPaiesMenuExpanded((v) => !v);
              }}
              onMouseEnter={() => isExpanded && setPaiesMenuExpanded(true)}
            >
              <span className="nav-icon">💶</span>
              <span className="nav-label">Paies</span>
              <span className="nav-chevron">{paiesMenuExpanded ? '▼' : '▶'}</span>
            </button>
            {paiesMenuExpanded && (
              <div className="nav-submenu">
                {filterSubmenuForAdmin(PAIES_MENU_ITEMS).map((item) => (
                  <Link
                    key={item.path}
                    to={item.path}
                    className={`nav-item nav-subitem ${location.pathname.includes(item.path) ? 'active' : ''}`}
                  >
                    <span className="nav-icon">{item.icon}</span>
                    <span className="nav-label">{item.label}</span>
                  </Link>
                ))}
              </div>
            )}
          </div>
        )}
        {isAdmin() && filterSubmenuForAdmin(FACTURATION_MENU_ITEMS).length > 0 && (
          <div className="nav-group admin-submenu">
            <button
              type="button"
              className={`nav-item nav-group-toggle ${facturationMenuExpanded ? 'expanded' : ''} ${FACTURATION_MENU_ITEMS.some((i) => location.pathname.includes(i.path)) ? 'active' : ''}`}
              onClick={() => {
                setIsExpanded(true);
                setFacturationMenuExpanded((v) => !v);
              }}
              onMouseEnter={() => isExpanded && setFacturationMenuExpanded(true)}
            >
              <span className="nav-icon">🧾</span>
              <span className="nav-label">Facturation</span>
              <span className="nav-chevron">{facturationMenuExpanded ? '▼' : '▶'}</span>
            </button>
            {facturationMenuExpanded && (
              <div className="nav-submenu">
                {filterSubmenuForAdmin(FACTURATION_MENU_ITEMS).map((item) => (
                  <Link
                    key={item.path}
                    to={item.path}
                    className={`nav-item nav-subitem ${location.pathname.includes(item.path) ? 'active' : ''}`}
                  >
                    <span className="nav-icon">{item.icon}</span>
                    <span className="nav-label">{item.label}</span>
                  </Link>
                ))}
              </div>
            )}
          </div>
        )}
        {/* Menu Social - visible uniquement pour l'admin */}
        {isAdmin() && (
          <div className="nav-group social-menu">
            <button
              type="button"
              className={`nav-item nav-group-toggle ${socialMenuExpanded ? 'expanded' : ''} ${SOCIAL_MENU_ITEMS.some(i => location.pathname.includes(i.path)) ? 'active' : ''}`}
              onClick={() => {
                setIsExpanded(true);
                setSocialMenuExpanded((v) => !v);
              }}
              onMouseEnter={() => isExpanded && setSocialMenuExpanded(true)}
            >
              <span className="nav-icon">👥</span>
              <span className="nav-label">Social</span>
              <span className="nav-chevron">{socialMenuExpanded ? '▼' : '▶'}</span>
            </button>
            {socialMenuExpanded && (
              <div className="nav-submenu">
                {SOCIAL_MENU_ITEMS.map((item) => (
                  <Link
                    key={item.path}
                    to={item.path}
                    className={`nav-item nav-subitem ${location.pathname.includes(item.path) ? 'active' : ''}`}
                  >
                    <span className="nav-icon">{item.icon}</span>
                    <span className="nav-label">{item.label}</span>
                  </Link>
                ))}
              </div>
            )}
          </div>
        )}
        {/* Items Social pour les salariés (affichés individuellement selon permissions) */}
        {getSocialItemsForEmployee().map((item) => (
          <Link
            key={item.path}
            to={item.path}
            className={`nav-item ${location.pathname.includes(item.path) ? 'active' : ''}`}
          >
            <span className="nav-icon">{item.icon}</span>
            <span className="nav-label">{item.label}</span>
          </Link>
        ))}
      </nav>
      
      <div className="sidebar-footer">
        <div className="user-info">
          {user && (
            <div className="user-role">
              <span className="user-icon">{isAdmin() ? '👑' : '👤'}</span>
              <span className="user-name">{user.name}</span>
            </div>
          )}
        </div>
        <div className="version-info">v2.1</div>
      </div>
    </div>
  );
};

export default Sidebar;

